const agentOutput   = $('AI Agent').first().json.output;
const totalBudget   = agentOutput.extractedContext.budget;
const tripDays      = agentOutput.extractedContext.days;
const preferences   = agentOutput.extractedContext.preferences.toLowerCase();
const destination   = agentOutput.extractedContext.destination;

const flightsNode   = $('Google_flights search').first().json;
const rawFlights    = flightsNode.best_flights || flightsNode.other_flights || []; 

const rawHotels     = $('Google_hotels search').first().json.properties || [];
const rawActivities = agentOutput?.output?.researchData?.activities || 
                     agentOutput?.research_data?.activities || [];

// TEMPORARY DEBUG — remove after confirming
const debugHotel = rawHotels[0] || {};
console.log('Hotel keys:', JSON.stringify(Object.keys(debugHotel)));
console.log('Hotel sample:', JSON.stringify({
  name: debugHotel.name,
  price: debugHotel.price,
  lowest: debugHotel.lowest,
  rate_per_night: debugHotel.rate_per_night,
  total_rate: debugHotel.total_rate,
  prices: debugHotel.prices
}));

// ── STEP 1: PREFERENCE-AWARE BUDGET SPLIT
let split = { flight: 0.35, hotel: 0.30, activity: 0.20, meals: 0.10, buffer: 0.05 };

if (preferences.includes('luxury')) {
    split = { flight: 0.35, hotel: 0.39, activity: 0.17, meals: 0.04, buffer: 0.05 };
} else if (preferences.includes('budget') || preferences.includes('backpack')) {
    split = { flight: 0.35, hotel: 0.19, activity: 0.32, meals: 0.09, buffer: 0.05 };
} else if (preferences.includes('foodie') || preferences.includes('food')) {
    split = { flight: 0.35, hotel: 0.26, activity: 0.13, meals: 0.22, buffer: 0.04 };
} else if (preferences.includes('adventure') || preferences.includes('outdoor')) {
    split = { flight: 0.35, hotel: 0.22, activity: 0.35, meals: 0.04, buffer: 0.04 };
}

// ── FIX: Compute limits directly from totalBudget (buffer is reserved, not deducted from limits)
const bufferReserve = totalBudget * split.buffer;
const flightLimit   = totalBudget * split.flight;
const hotelLimit    = totalBudget * split.hotel;
const activityLimit = totalBudget * split.activity;
const mealLimit     = totalBudget * split.meals;
// These 5 categories sum to 100% of totalBudget

const mealPerDay    = mealLimit / tripDays;

// ── STEP 2: SMART FLIGHT FILTER
function filterFlights(flights, limit) {
  let filtered = flights
    .filter(f => f.price <= limit)
    .sort((a, b) => {
      const priceScoreA = a.price / limit;
      const priceScoreB = b.price / limit;
      const durScoreA   = (a.total_duration || 1800) / 1800;
      const durScoreB   = (b.total_duration || 1800) / 1800;
      return (priceScoreA + durScoreA * 0.3) - (priceScoreB + durScoreB * 0.3);
    })
    .slice(0, 5);

  if (filtered.length === 0) {
    filtered = flights
      .filter(f => f.price <= limit * 1.20)
      .sort((a, b) => a.price - b.price)
      .slice(0, 3);
    return { data: filtered, relaxed: true, relaxed_by: '20%' };
  }
  return { data: filtered, relaxed: false };
}

// ── STEP 3: SMART HOTEL FILTER
function filterHotels(hotels, limit, days) {
  const withTotal = hotels.map(h => {

    // Walk every possible path SerpAPI uses for price
    let pricePerNight = 0;

    // Structure 1: rate_per_night object
    if (h.rate_per_night) {
      pricePerNight = h.rate_per_night.extracted_lowest
        || parseFloat(String(h.rate_per_night.lowest  || '0').replace(/[^0-9.]/g, ''))
        || 0;
    }

    // Structure 2: total_rate object (divide by days to get per-night)
    if (!pricePerNight && h.total_rate) {
      const totalExtracted = h.total_rate.extracted_lowest
        || parseFloat(String(h.total_rate.lowest || '0').replace(/[^0-9.]/g, ''))
        || 0;
      pricePerNight = days > 0 ? totalExtracted / days : 0;
    }

    // Structure 3: prices array (SerpAPI sometimes returns this)
    if (!pricePerNight && Array.isArray(h.prices) && h.prices.length > 0) {
      const firstPrice = h.prices[0];
      pricePerNight = firstPrice.extracted_lowest
        || firstPrice.rate_per_night?.extracted_lowest
        || parseFloat(String(firstPrice.lowest || firstPrice.rate || '0').replace(/[^0-9.]/g, ''))
        || 0;
    }

    // Structure 4: flat fields directly on the hotel object
    if (!pricePerNight) {
      const flat = h.price || h.lowest || h.nightly_price || '0';
      pricePerNight = parseFloat(String(flat).replace(/[^0-9.]/g, '')) || 0;
    }

    const totalStayCost = pricePerNight * days;

    return {
      ...h,
      total_stay_cost    : totalStayCost,
      price_per_night_num: pricePerNight,
      rating_num         : parseFloat(h.overall_rating || 0)
    };
  });

  // Log parsed prices so you can see what's happening in n8n execution log
  console.log('Hotel prices parsed:', withTotal.map(h => ({
    name : h.name,
    ppn  : h.price_per_night_num,
    total: h.total_stay_cost
  })));

  let filtered = withTotal
    .filter(h => h.total_stay_cost > 0 && h.total_stay_cost <= limit)
    .sort((a, b) => {
      const valueA = a.rating_num / (a.price_per_night_num || 1);
      const valueB = b.rating_num / (b.price_per_night_num || 1);
      return valueB - valueA;
    })
    .slice(0, 5);

  if (filtered.length === 0) {
    // Relaxed pass — also require price > 0 so zero-price ghost hotels don't sneak in
    filtered = withTotal
      .filter(h => h.total_stay_cost > 0 && h.total_stay_cost <= limit * 1.20)
      .sort((a, b) => a.total_stay_cost - b.total_stay_cost)
      .slice(0, 3);

    if (filtered.length === 0) {
      // Nothing has a price at all — SerpAPI didn't return pricing
      // Return raw hotels with a flag so the warning fires
      return { data: [], relaxed: true, relaxed_by: '20%', no_pricing: true };
    }

    return { data: filtered, relaxed: true, relaxed_by: '20%' };
  }

  return { data: filtered, relaxed: false };
}
// ── STEP 4: ACTIVITY FILTER
function getTypePriority(prefs) {
  if (prefs.includes('culture') || prefs.includes('history')) return { culture: 5, landmark: 4, adventure: 2, relaxation: 1 };
  if (prefs.includes('adventure') || prefs.includes('outdoor')) return { adventure: 5, landmark: 3, culture: 2, relaxation: 1 };
  if (prefs.includes('luxury') || prefs.includes('relax')) return { relaxation: 5, landmark: 3, culture: 2, adventure: 1 };
  return { landmark: 4, culture: 3, adventure: 3, relaxation: 2 };
}

function filterActivities(activities, limit, preferences) {
  const typePriority = getTypePriority(preferences);
  const scored = activities.map(a => ({ ...a, priority_score: typePriority[a.type] || 1 }));
  scored.sort((a, b) => (b.priority_score !== a.priority_score) ? b.priority_score - a.priority_score : a.approx_cost - b.approx_cost);

  let spent = 0;
  const selected = [];
  for (const act of scored) {
    if (spent + act.approx_cost <= limit) {
      spent += act.approx_cost;
      selected.push(act);
    }
  }
  return { data: selected, actual_spend: spent };
}

// ── RUN ALL FILTERS
const flightResult   = filterFlights(rawFlights, flightLimit);
const hotelResult    = filterHotels(rawHotels, hotelLimit, tripDays);
const activityResult = filterActivities(rawActivities, activityLimit, preferences);

// ── STEP 5: BUDGET HEALTH SCORE
// ── FIX: Use actual data values; fall back to limit if no results returned
const cheapestFlightCost  = flightResult.data.length > 0  ? flightResult.data[0].price               : flightLimit;
const cheapestHotelCost   = hotelResult.data.length  > 0  ? hotelResult.data[0].total_stay_cost       : hotelLimit;
const activitySpend       = activityResult.actual_spend;

// estimated_total is a realistic projection: cheapest flight + cheapest hotel + activities + full meal budget
const estimatedTotal  = cheapestFlightCost + cheapestHotelCost + activitySpend + mealLimit;
const remaining       = totalBudget - estimatedTotal;
const healthPct       = Math.round((remaining / totalBudget) * 100);

let healthLabel = '';
let healthAdvice = '';
if (healthPct >= 20) {
  healthLabel = 'Excellent';
  healthAdvice = `₹${remaining.toFixed(0)} breathing room — consider upgrading hotel or adding experiences.`;
} else if (healthPct >= 10) {
  healthLabel = 'Good';
  healthAdvice = `₹${remaining.toFixed(0)} spare. Stay on budget for meals and transport.`;
} else if (healthPct >= 0) {
  healthLabel = 'Tight';
  healthAdvice = `Trip fits budget but barely. Watch daily spending carefully.`;
} else {
  healthLabel = 'Over Budget';
  healthAdvice = `Exceeds budget by ₹${Math.abs(remaining).toFixed(0)}. Consider cheaper flights or hotel.`;
}

// Warnings
const warnings = [];
if (flightResult.relaxed)  warnings.push(`Flight budget relaxed by 20% — cheapest option is ₹${cheapestFlightCost.toFixed(0)}`);
if (hotelResult.relaxed)   warnings.push(`Hotel budget relaxed by 20% — cheapest option is ₹${cheapestHotelCost.toFixed(0)}`);
if (flightResult.data.length === 0) warnings.push('No flights found — check departure/arrival airport codes');
if (hotelResult.data.length === 0)  warnings.push('No hotels found — check destination search query');

// ── FINAL OUTPUT
return [{
  json: {
    budget_summary: {
      total_budget   : totalBudget,
      limits: {
        flightLimit,
        hotelLimit,
        activityLimit,
        mealLimit,
        bufferReserve   // ← NEW: clearly shows what's held back
      },
      estimated_costs: {               // ← NEW: separate from limits so Agent Pass 2 can display both
        flight   : cheapestFlightCost,
        hotel    : cheapestHotelCost,
        activities: activitySpend,
        meals    : mealLimit,
        total    : parseFloat(estimatedTotal.toFixed(0))
      },
      estimated_total : parseFloat(estimatedTotal.toFixed(0)),
      remaining       : parseFloat(remaining.toFixed(0)),        // ← FIX: now exists on the object
      health_score    : healthLabel,
      health_advice   : healthAdvice,
      warnings
    },
    options: {
      flights    : flightResult.data,
      hotels     : hotelResult.data,
      activities : activityResult.data
    }
  }
}];

// ── GEOCODING NODE ──────────────────────────────────────────
// Reads from Budget Guard output
// Activities & restaurants have no lat/lng (came from Tavily via Agent)
// Hotels already have gps_coordinates from SerpApi → skip them
// Uses Nominatim (OpenStreetMap) — free, no API key needed
// Rate limit: 1 request per second (required by Nominatim ToS)
// ────────────────────────────────────────────────────────────

const input = $input.first().json;

const destination = $('AI Agent').first().json.output.extractedContext.destination;

const activities  = input.options.activities  || [];
const hotels      = input.options.hotels      || [];
const budgetSummary = input.budget_summary;

// ── Helper: sleep to respect Nominatim 1 req/sec rate limit
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// ── Helper: fetch lat/lng from Nominatim for a place name
async function geocode(placeName, destination) {
  const query = encodeURIComponent(`${placeName}, ${destination}`);
  const url = `https://nominatim.openstreetmap.org/search?q=${query}&format=json&limit=1`;

  try {
    const response = await $http.request({
      method: 'GET',
      url: url,
      headers: {
        // Nominatim requires a User-Agent identifying your app
        'User-Agent': 'TravelPlannerApp/1.0 (travel-planner@example.com)'
      }
    });

    if (response && response.length > 0) {
      return {
        lat: parseFloat(response[0].lat),
        lng: parseFloat(response[0].lon)
      };
    }
  } catch (err) {
    // If geocoding fails for a place, return null coords
    // Pathfinder will skip places with null coords
    console.log(`Geocoding failed for: ${placeName} — ${err.message}`);
  }

  return { lat: null, lng: null };
}

// ── 1. GEOCODE ACTIVITIES
const geocodedActivities = [];

for (const activity of activities) {
  const coords = await geocode(activity.name, destination);
  geocodedActivities.push({
    ...activity,
    lat: coords.lat,
    lng: coords.lng
  });
  // Wait 1.1 seconds between requests — Nominatim hard requirement
  await sleep(1100);
}

// ── 2. HOTELS — already have gps_coordinates from SerpApi
// Just reshape to flat lat/lng fields so Pathfinder has
// a consistent structure across all place types
const geocodedHotels = hotels.map(hotel => {
  // SerpApi returns: hotel.gps_coordinates.latitude / .longitude
  const coords = hotel.gps_coordinates || {};
  return {
    ...hotel,
    lat: coords.latitude  || null,
    lng: coords.longitude || null
  };
});

// ── 3. RESTAURANTS — from AI Agent researchData
// Budget Guard only passes activities and hotels
// Restaurants come directly from Agent output
const rawRestaurants = $('AI Agent').first().json.output.researchData.restaurants || [];

const geocodedRestaurants = [];

for (const restaurant of rawRestaurants) {
  const coords = await geocode(restaurant.name, destination);
  geocodedRestaurants.push({
    ...restaurant,
    lat: coords.lat,
    lng: coords.lng
  });
  await sleep(1100);
}

// ── FINAL OUTPUT
// Passes everything the Pathfinder needs:
// all places with lat/lng, budget summary, hotel as anchor
return {
  budget_summary: budgetSummary,

  // Pathfinder uses the first hotel as the day anchor point
  selected_hotel: geocodedHotels[0] || null,

  all_hotels: geocodedHotels,

  activities: geocodedActivities,

  restaurants: geocodedRestaurants,

  // Pass through destination and days for Pathfinder logic
  meta: {
    destination: destination,
    days: $('AI Agent').first().json.output.extractedContext.days,
    preferences: $('AI Agent').first().json.output.extractedContext.preferences
  }
};

// ── PATHFINDER NODE ─────────────────────────────────────────
// Receives geocoded places from Geocoding Node
// Uses Haversine distance to cluster and sort activities
// into a realistic day-by-day walking route
// ─────────────────────────────────────────────────────────────

const input = $input.first().json;

const hotel      = input.selected_hotel;
const activities = input.activities   || [];
const restaurants= input.restaurants  || [];
const meta       = input.meta;
const budget     = input.budget_summary;

const totalDays  = meta.days;

// ─────────────────────────────────────────────────────────────
// STEP 1 — HAVERSINE FORMULA
// Calculates straight-line distance in KM between two coords
// ─────────────────────────────────────────────────────────────

function haversine(lat1, lng1, lat2, lng2) {
  // If either point has no coords, return a large number
  // so null-coord places sort to the end and don't break math
  if (lat1 == null || lng1 == null || lat2 == null || lng2 == null) {
    return 9999;
  }

  const R    = 6371; // Earth radius in km
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;

  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(lat1 * Math.PI / 180) *
    Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLng / 2) * Math.sin(dLng / 2);

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c; // distance in km
}

// ─────────────────────────────────────────────────────────────
// STEP 2 — SORT ALL ACTIVITIES BY DISTANCE FROM HOTEL
// This gives us a rough "how far is everything" baseline
// ─────────────────────────────────────────────────────────────

const hotelLat = hotel ? hotel.lat : null;
const hotelLng = hotel ? hotel.lng : null;

const activitiesWithDistance = activities.map(act => ({
  ...act,
  dist_from_hotel_km: haversine(hotelLat, hotelLng, act.lat, act.lng)
}));

// Sort by distance from hotel ascending
activitiesWithDistance.sort((a, b) => a.dist_from_hotel_km - b.dist_from_hotel_km);

// ─────────────────────────────────────────────────────────────
// STEP 3 — CLUSTER ACTIVITIES INTO DAYS
// Split the sorted activity list into N equal day buckets
// Activities closest to hotel go on day 1, furthest on last day
// This naturally groups nearby activities together
// ─────────────────────────────────────────────────────────────

// How many activities per day (distribute evenly)
const perDay = Math.ceil(activitiesWithDistance.length / totalDays);

const dayClusters = [];
for (let d = 0; d < totalDays; d++) {
  const start = d * perDay;
  const end   = start + perDay;
  dayClusters.push(activitiesWithDistance.slice(start, end));
}

// ─────────────────────────────────────────────────────────────
// STEP 4 — NEAREST NEIGHBOUR SORT WITHIN EACH DAY
// Within each day's cluster, find the most efficient
// walking order starting from the hotel
// ─────────────────────────────────────────────────────────────

function nearestNeighbourSort(stops, startLat, startLng) {
  const remaining = [...stops];
  const ordered   = [];

  let currentLat = startLat;
  let currentLng = startLng;

  while (remaining.length > 0) {
    // Find the closest unvisited stop from current position
    let closestIdx  = 0;
    let closestDist = haversine(currentLat, currentLng, remaining[0].lat, remaining[0].lng);

    for (let i = 1; i < remaining.length; i++) {
      const dist = haversine(currentLat, currentLng, remaining[i].lat, remaining[i].lng);
      if (dist < closestDist) {
        closestDist = dist;
        closestIdx  = i;
      }
    }

    const next = remaining.splice(closestIdx, 1)[0];
    ordered.push({
      ...next,
      dist_from_prev_km: parseFloat(closestDist.toFixed(2))
    });

    // Move current position to the stop we just added
    currentLat = next.lat;
    currentLng = next.lng;
  }

  return ordered;
}

// ─────────────────────────────────────────────────────────────
// STEP 5 — ASSIGN TIMES TO EACH STOP
// Start at 9:00 AM each day
// Each activity takes duration_hrs
// Add 20 min travel buffer between stops
// ─────────────────────────────────────────────────────────────

function assignTimes(orderedStops) {
  // Start time: 9:00 AM in minutes from midnight
  let currentMinutes = 9 * 60;

  return orderedStops.map((stop, idx) => {
    const hours   = Math.floor(currentMinutes / 60);
    const minutes = currentMinutes % 60;
    const timeStr = `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;

    const stopWithTime = {
      ...stop,
      suggested_arrival: timeStr,
      order: idx + 1
    };

    // Advance time by activity duration + 20 min travel buffer
    const durationMins = (stop.duration_hrs || 1) * 60;
    currentMinutes += durationMins + 20;

    return stopWithTime;
  });
}

// ─────────────────────────────────────────────────────────────
// STEP 6 — FIND NEAREST DINNER RESTAURANT FOR EACH DAY
// After all activities are done, find the restaurant
// closest to the last activity of that day
// ─────────────────────────────────────────────────────────────

function findDinnerStop(lastStop, restaurants, usedRestaurantNames) {
  if (!restaurants || restaurants.length === 0) return null;

  // Filter out already used restaurants (one per day)
  const available = restaurants.filter(r => !usedRestaurantNames.has(r.name));
  if (available.length === 0) return null;

  const lastLat = lastStop ? lastStop.lat : hotelLat;
  const lastLng = lastStop ? lastStop.lng : hotelLng;

  // Find closest available restaurant to last activity
  const sorted = available
    .map(r => ({
      ...r,
      dist_from_prev_km: parseFloat(
        haversine(lastLat, lastLng, r.lat, r.lng).toFixed(2)
      )
    }))
    .sort((a, b) => a.dist_from_prev_km - b.dist_from_prev_km);

  return sorted[0];
}

// ─────────────────────────────────────────────────────────────
// STEP 7 — BUILD FINAL DAY-BY-DAY ITINERARY
// ─────────────────────────────────────────────────────────────

const usedRestaurantNames = new Set();
const itinerary = [];

for (let d = 0; d < totalDays; d++) {
  const cluster = dayClusters[d] || [];

  // Nearest-neighbour sort starting from hotel
  const orderedStops = nearestNeighbourSort(cluster, hotelLat, hotelLng);

  // Assign suggested arrival times
  const timedStops = assignTimes(orderedStops);

  // Calculate day cost (sum of all activity costs)
  const activityCostToday = timedStops.reduce(
    (sum, s) => sum + (s.approx_cost || 0), 0
  );

  // Find dinner restaurant near last stop of the day
  const lastStop = timedStops[timedStops.length - 1] || null;
  const dinner   = findDinnerStop(lastStop, restaurants, usedRestaurantNames);

  if (dinner) {
    usedRestaurantNames.add(dinner.name);

    // 1. Get the last stop's time, or default to 18:00 (6 PM) if no activities exist
    const lastStopTime  = lastStop ? lastStop.suggested_arrival : '18:00';
    const [lh, lm]      = lastStopTime.split(':').map(Number);

    // 2. Safely get duration: use lastStop.duration_hrs if it exists, otherwise default to 0
    const lastStopDuration = lastStop?.duration_hrs || 0;

    // 3. Calculate dinner start (Last activity end + 20 min buffer)
    const lastEndMins   = (lh * 60) + lm + (lastStopDuration * 60) + 20;

    const dinnerHours   = Math.floor(lastEndMins / 60);
    const dinnerMinutes = lastEndMins % 60;

    dinner.suggested_arrival = `${String(dinnerHours).padStart(2, '0')}:${String(dinnerMinutes).padStart(2, '0')}`;
    dinner.order        = timedStops.length + 1;
    dinner.type         = 'dinner';
  }

  // Total day cost including dinner
  const dinnerCost    = dinner ? (dinner.approx_cost_per_person || 0) : 0;
  const totalDayCost  = activityCostToday + dinnerCost;

  // Total walking distance for the day
  const totalWalkingKm = timedStops.reduce(
    (sum, s) => sum + (s.dist_from_prev_km || 0), 0
  );

  itinerary.push({
    day: d + 1,
    day_label: `Day ${d + 1}`,
    hotel_base: hotel ? hotel.name : 'Selected Hotel',
    stops: timedStops,
    dinner: dinner,
    day_summary: {
      total_activities : timedStops.length,
      activity_cost_usd: parseFloat(activityCostToday.toFixed(2)),
      dinner_cost_usd  : parseFloat(dinnerCost.toFixed(2)),
      total_day_cost_usd: parseFloat(totalDayCost.toFixed(2)),
      total_walking_km : parseFloat(totalWalkingKm.toFixed(2))
    }
  });
}

// ─────────────────────────────────────────────────────────────
// STEP 8 — TRIP SUMMARY
// ─────────────────────────────────────────────────────────────

const totalActivityCost = itinerary.reduce(
  (sum, day) => sum + day.day_summary.activity_cost_usd, 0
);
const totalDinnerCost = itinerary.reduce(
  (sum, day) => sum + day.day_summary.dinner_cost_usd, 0
);
const totalWalking = itinerary.reduce(
  (sum, day) => sum + day.day_summary.total_walking_km, 0
);

// ─────────────────────────────────────────────────────────────
// FINAL OUTPUT — everything Agent Pass 2 needs
// ─────────────────────────────────────────────────────────────

return {
  meta: {
    destination : meta.destination,
    days        : totalDays,
    preferences : meta.preferences
  },

  hotel: {
    name           : hotel ? hotel.name : null,
    price_per_night: hotel ? hotel.rate_per_night : null,
    rating         : hotel ? hotel.overall_rating  : null,
    neighborhood   : hotel ? hotel.neighborhood    : null,
    lat            : hotelLat,
    lng            : hotelLng
  },

  itinerary: itinerary,

  trip_summary: {
    total_days          : totalDays,
    total_activity_cost : parseFloat(totalActivityCost.toFixed(2)),
    total_dinner_cost   : parseFloat(totalDinnerCost.toFixed(2)),
    total_walking_km    : parseFloat(totalWalking.toFixed(2)),
    flight_budget_limit : budget.limits.flightLimit,
    hotel_budget_limit  : budget.limits.hotelLimit,
    activity_budget_used: parseFloat((budget.total_budget -budget.remaining).toFixed(2))
  },

  // Pass through for Agent Pass 2 prompt
  budget_summary: budget
};

const CHUNK_SIZE = 500;

const researchData = $('AI Agent').first().json.output.researchData;
const activities   = researchData.activities   || [];
const restaurants  = researchData.restaurants  || [];
const localTips    = researchData.local_tips   || [];
const transport    = researchData.transport_notes || '';

// NOTE: Tavily tool returns source_url per activity
// Your Agent Pass 1 system prompt must include source_url
// in the output schema — add this field to your JSON schema:
// "source_url": string  (URL Tavily found this info from)
// "source_name": string (domain name, e.g. "tripadvisor.com")

const allPlaces = [
  ...activities.map(a => ({
    place_name  : a.name,
    type        : a.type || 'activity',
    text        : a.description || '',
    source_url  : a.source_url  || null,
    source_name : a.source_name || extractDomain(a.source_url)
  })),
  ...restaurants.map(r => ({
    place_name  : r.name,
    type        : 'restaurant',
    text        : r.description || '',
    source_url  : r.source_url  || null,
    source_name : r.source_name || extractDomain(r.source_url)
  })),
  {
    place_name  : 'Local Tips & Transport',
    type        : 'tips',
    text        : [...localTips, transport].join('. '),
    source_url  : null,
    source_name : null
  }
];

function extractDomain(url) {
  if (!url) return null;
  try {
    const hostname = new URL(url).hostname;
    return hostname.replace('www.', '');
  } catch {
    return null;
  }
}

const chunks = [];

for (const place of allPlaces) {
  const text = place.text.replace(/\s+/g, ' ').trim();
  if (!text) continue;

  const sentences = text.match(/[^.!?]+[.!?]+/g) || [text];
  let currentChunk = '';

  for (const sentence of sentences) {
    if ((currentChunk + sentence).length > CHUNK_SIZE) {
      if (currentChunk.trim()) {
        chunks.push({
          json: {
            place_name  : place.place_name,
            type        : place.type,
            text        : currentChunk.trim(),
            char_count  : currentChunk.trim().length,
            // ← CITATION FIELDS carried on every chunk
            source_url  : place.source_url,
            source_name : place.source_name
          }
        });
      }
      currentChunk = sentence;
    } else {
      currentChunk += ' ' + sentence;
    }
  }

  if (currentChunk.trim()) {
    chunks.push({
      json: {
        place_name  : place.place_name,
        type        : place.type,
        text        : currentChunk.trim(),
        char_count  : currentChunk.trim().length,
        source_url  : place.source_url,
        source_name : place.source_name
      }
    });
  }
}

if (chunks.length === 0) {
  return [{
    json: {
      place_name  : 'fallback',
      type        : 'tips',
      text        : 'No description content available.',
      char_count  : 0,
      source_url  : null,
      source_name : null
    }
  }];
}

return chunks;

const chunks    = $input.all();
const agentCtx  = $('AI Agent').first().json.output.extractedContext;

const userQuery = `${agentCtx.days} day trip to ${agentCtx.destination}, `
                + `preferences: ${agentCtx.preferences}, `
                + `budget: $${agentCtx.budget}`;

const chunkRequests = chunks.map(item => ({
  model    : 'models/text-embedding-004',
  content  : { parts: [{ text: item.json.text }] },
  task_type: 'RETRIEVAL_DOCUMENT',
  title    : item.json.place_name
}));

const queryRequest = {
  model    : 'models/text-embedding-004',
  content  : { parts: [{ text: userQuery }] },
  task_type: 'RETRIEVAL_QUERY'
};

const allRequests = [...chunkRequests, queryRequest];

return [{
  json: {
    requests    : allRequests,
    chunk_count : chunkRequests.length,
    query_index : allRequests.length - 1,
    // ← source_url and source_name now carried forward
    chunk_metadata: chunks.map(c => ({
      place_name  : c.json.place_name,
      type        : c.json.type,
      text        : c.json.text,
      source_url  : c.json.source_url,
      source_name : c.json.source_name
    })),
    user_query  : userQuery
  }
}];

function cosine(a, b) {
  let dot = 0, mA = 0, mB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    mA  += a[i] * a[i];
    mB  += b[i] * b[i];
  }
  const denom = Math.sqrt(mA) * Math.sqrt(mB);
  return denom === 0 ? 0 : dot / denom;
}

const batchResponse = $input.first().json.embeddings;

if (!batchResponse || batchResponse.length === 0) {
  throw new Error('Batch Embedder returned no embeddings');
}

const packerData    = $('packer').first().json;
const chunkMetadata = packerData.chunk_metadata;
const queryIndex    = packerData.query_index;
const chunkCount    = packerData.chunk_count;

const queryVector  = batchResponse[queryIndex].values;
const chunkVectors = batchResponse.slice(0, chunkCount);

// Score every chunk
const scored = chunkVectors.map((emb, idx) => {
  const meta  = chunkMetadata[idx];
  const score = cosine(queryVector, emb.values);
  return {
    place_name  : meta.place_name,
    type        : meta.type,
    text        : meta.text,
    score       : parseFloat(score.toFixed(4)),
    source_url  : meta.source_url  || null,
    source_name : meta.source_name || null
  };
});

scored.sort((a, b) => b.score - a.score);

const TOP_K    = 15;
const topChunks = scored.slice(0, TOP_K);

// Group by place — build rag_context_text WITH inline citations
const byPlace = {};
for (const chunk of topChunks) {
  if (!byPlace[chunk.place_name]) {
    byPlace[chunk.place_name] = {
      texts      : [],
      source_url : chunk.source_url,
      source_name: chunk.source_name
    };
  }
  byPlace[chunk.place_name].texts.push(chunk.text);
}

// Build context text — each place section ends with its source
const rag_context_text = Object.entries(byPlace)
  .map(([place, data]) => {
    const citation = data.source_url
      ? `\n[Source: ${data.source_name || data.source_url}](${data.source_url})`
      : '';
    return `### ${place}\n${data.texts.join(' ')}${citation}`;
  })
  .join('\n\n');

// Build deduplicated citations list for frontend display
const citationsMap = {};
for (const chunk of topChunks) {
  if (chunk.source_url && !citationsMap[chunk.source_url]) {
    citationsMap[chunk.source_url] = {
      place_name  : chunk.place_name,
      source_name : chunk.source_name || chunk.source_url,
      source_url  : chunk.source_url,
      score       : chunk.score
    };
  }
}
const citations = Object.values(citationsMap)
  .sort((a, b) => b.score - a.score);

// Pull pathfinder output
const pathfinderOutput = $('PathFinder').first().json;

return [{
  json: {
    rag_context_text,
    citations,        // ← NEW: array of {place_name, source_name, source_url, score}
    top_chunks  : topChunks,
    itinerary   : pathfinderOutput.itinerary,
    hotel       : pathfinderOutput.hotel,
    trip_summary: pathfinderOutput.trip_summary,
    budget_summary: pathfinderOutput.budget_summary,
    flights     : $('link_generator').first().json.options.flights,
    hotels      : $('link_generator').first().json.options.hotels,
    meta        : pathfinderOutput.meta
  }
}];

