// --- INPUT VALIDATOR: ENSURE DATA INTEGRITY ---
const input = $input.first().json.chatInput|| ""; // From Chat Trigger
const state = $node["Window Buffer Memory"].json || {}; // Check existing memory

// Define mandatory fields
