if (!state.destination && !input.toLowerCase().includes("to")) missing.push("destination");
if (!state.budget && !input.match(/\d+/)) missing.push("budget");
if (!state.dates && !input.toLowerCase().includes("day")) missing.push("trip duration/dates");

return {
