  missingFields: missing,
  promptUser: missing.length > 0 ? `I'd love to help! I just need your ${missing.join(", ")} to get started.` : null
};

const input       = $input.first().json;
const agentOutput = $('AI Agent').first().json.output;
const destination = agentOutput.extractedContext.destination;
const startDate   = agentOutput.extractedContext.startDate   || '';
const endDate     = agentOutput.extractedContext.endDate     || '';
const travelers   = agentOutput.extractedContext.travelers   || 2;
const origin      = agentOutput.extractedContext.origin      || '';

// ── AIRLINE DIRECT BOOKING LINKS
// Fallback map when booking_token is not available
function getAirlineLink(airline = '') {
  const map = {
    'indigo'          : 'https://www.goindigo.in',
    'air india'       : 'https://www.airindia.com',
    'vistara'         : 'https://www.airvistara.com',
    'spicejet'        : 'https://www.spicejet.com',
    'emirates'        : 'https://www.emirates.com',
    'qatar airways'   : 'https://www.qatarairways.com',
    'lufthansa'       : 'https://www.lufthansa.com',
    'british airways' : 'https://www.britishairways.com',
    'ita airways'     : 'https://www.itaairways.com',
    'air france'      : 'https://www.airfrance.com',
    'klm'             : 'https://www.klm.com',
    'turkish airlines': 'https://www.turkishairlines.com',
    'etihad'          : 'https://www.etihad.com',
    'singapore airlines': 'https://www.singaporeair.com'
  };
  const key = airline.toLowerCase();
  for (const [name, url] of Object.entries(map)) {
    if (key.includes(name)) return url;
  }
  return null;
}

// ── 1. FLIGHTS WITH LINKS
const flightsWithLinks = (input.options.flights || []).map(f => {
  // SerpApi returns booking_token for Google Flights deep link
  const token = f.booking_token || null;

  // Google Flights deep link using token (most accurate)
  const googleFlightsLink = token
    ? `https://www.google.com/travel/flights?tfs=${token}`
    : null;

  // Google Flights search fallback (no token)
  const googleFlightsSearch = `https://www.google.com/travel/flights/search` +
    `?q=Flights+from+${encodeURIComponent(origin)}` +
    `+to+${encodeURIComponent(destination)}` +
    `+on+${startDate}`;

  // Airline direct site fallback
  const airlineLink = getAirlineLink(f.airline);

  // Best available link — token first, then search, then airline
  const best_booking_link = googleFlightsLink
    || googleFlightsSearch;

  return {
    ...f,
    links: {
      google_flights : googleFlightsLink || googleFlightsSearch,
      airline_site   : airlineLink,
      best_link      : best_booking_link,
      label          : `Book ${f.airline} — $${f.price}`
    }
  };
});

// ── 2. HOTELS WITH LINKS
const hotelsWithLinks = (input.options.hotels || []).map(h => {
  const hotelNameEncoded = encodeURIComponent(h.name + ' ' + destination);
  const destEncoded      = encodeURIComponent(destination);

  // SerpApi google_hotels returns h.link directly — real Google Hotels page
  const googleHotelsLink = h.link || null;

  // Booking.com search link (always works as fallback)
  const bookingComLink = `https://www.booking.com/search.html` +
    `?ss=${hotelNameEncoded}` +
    `&checkin=${startDate}` +
    `&checkout=${endDate}` +
    `&group_adults=${travelers}` +
    `&no_rooms=1`;

  // Google Maps link — use coordinates if available, else name search
  const mapsLink = (h.gps_coordinates?.latitude && h.gps_coordinates?.longitude)
    ? `https://www.google.com/maps?q=${h.gps_coordinates.latitude},${h.gps_coordinates.longitude}`
    : `https://www.google.com/maps/search/${hotelNameEncoded}`;

  // Best booking link — Google Hotels page first, then Booking.com
  const best_booking_link = googleHotelsLink || bookingComLink;

  return {
    ...h,
    links: {
      google_hotels : googleHotelsLink,
      booking_com   : bookingComLink,
      google_maps   : mapsLink,
      best_link     : best_booking_link,
      label         : `Book ${h.name} — $${h.price_per_night_num}/night`
    }
  };
});

// ── 3. ACTIVITIES WITH LINKS
// Activities come from Tavily text so no booking token
// Just attach a Maps search link per activity
const activitiesWithLinks = (input.options.activities || []).map(a => {
  const nameEncoded = encodeURIComponent(a.name + ' ' + destination);

  // Google Maps search for the place
  const mapsLink = `https://www.google.com/maps/search/${nameEncoded}`;

  // Viator link for bookable tours/tickets
  const viatorLink = `https://www.viator.com/search/${nameEncoded}`;

  return {
    ...a,
    links: {
      google_maps : mapsLink,
      book_tour   : viatorLink,
      label       : a.name
    }
  };
});


// budget_summary stays intact for Agent Pass 2
return [{
  json: {
    budget_summary : input.budget_summary,
    options: {
      flights    : flightsWithLinks,
      hotels     : hotelsWithLinks,
      activities : activitiesWithLinks
    }
  }
}];

