const forecast = $input.first().json;
const tripDays = $('AI Agent').first().json.output.extractedContext.days;
const startDate = $('AI Agent').first().json.output.extractedContext.startDate
                  || new Date().toISOString().split('T')[0];

// OpenWeatherMap returns 3-hour intervals (list[])
// Group them by day
const byDay = {};

for (const entry of (forecast.list || [])) {
  // entry.dt_txt = "2026-04-24 09:00:00"
  const day = entry.dt_txt.split(' ')[0];
  if (!byDay[day]) byDay[day] = [];
  byDay[day].push(entry);
}

// Build one summary per day
const dailySummaries = Object.entries(byDay)
  .slice(0, tripDays) // only as many days as the trip
  .map(([date, entries], index) => {
    // Average temp across the day
    const avgTemp = entries.reduce((sum, e) =>
      sum + e.main.temp, 0) / entries.length;

    // Most common weather condition
    const conditionCounts = {};
    for (const e of entries) {
      const desc = e.weather[0].description;
      conditionCounts[desc] = (conditionCounts[desc] || 0) + 1;
    }
    const dominantCondition = Object.entries(conditionCounts)
      .sort((a, b) => b[1] - a[1])[0][0];

    // Check for rain
    const hasRain = entries.some(e =>
      e.weather[0].main.toLowerCase().includes('rain') ||
      e.weather[0].main.toLowerCase().includes('drizzle')
    );

    // Max wind speed
    const maxWind = Math.max(...entries.map(e => e.wind?.speed || 0));

    // Humidity average
    const avgHumidity = entries.reduce((sum, e) =>
      sum + e.main.humidity, 0) / entries.length;

    // Human readable advice for Agent Pass 2
    let packingTip = '';
    if (hasRain) {
      packingTip = 'Bring a compact umbrella or light rain jacket.';
    } else if (avgTemp > 30) {
      packingTip = 'Very hot — wear sunscreen, carry water, visit indoor spots midday.';
    } else if (avgTemp < 10) {
      packingTip = 'Cold day — layer up with a warm jacket.';
    } else {
      packingTip = 'Pleasant weather — comfortable for walking and outdoor activities.';
    }

    // Outdoor activity suitability
    const outdoorSuitable = !hasRain && avgTemp > 10 && avgTemp < 35;

    return {
      day_number       : index + 1,
      date             : date,
      avg_temp_c       : parseFloat(avgTemp.toFixed(1)),
      condition        : dominantCondition,
      has_rain         : hasRain,
      max_wind_kph     : parseFloat((maxWind * 3.6).toFixed(1)),
      avg_humidity_pct : Math.round(avgHumidity),
      outdoor_suitable : outdoorSuitable,
      packing_tip      : packingTip
    };
  });

// Overall trip weather summary
const rainyDays  = dailySummaries.filter(d => d.has_rain).length;
const avgTripTemp = dailySummaries.reduce((s, d) =>
  s + d.avg_temp_c, 0) / (dailySummaries.length || 1);

return [{
  json: {
    city          : forecast.city?.name || '',
    country       : forecast.city?.country || '',
    daily         : dailySummaries,
    trip_summary  : {
      avg_temp_c    : parseFloat(avgTripTemp.toFixed(1)),
      rainy_days    : rainyDays,
      overall_advice: rainyDays > 2
        ? 'Pack for mixed weather — rain on several days expected.'
        : avgTripTemp > 28
          ? 'Hot trip — light clothing and sun protection essential.'
          : 'Generally good weather expected for your trip.'
    }
  }
}];
